import pytest

def test_submit_valid_timesheet_mid_range(auth_session, totp_code, clean_timesheet_week):
    payload = {
        "week_start": clean_timesheet_week,
        "days": {"mon": 8, "tue": 8, "wed": 8, "thu": 8, "fri": 8, "sat": 8, "sun": 8},
        "two_factor_code": totp_code()
    }
    resp = auth_session.post("/timesheets/submit", json=payload)
    assert resp.status_code == 200
    body = resp.json()
    assert body["state"] == "submitted"
    for day, hours in payload["days"].items():
        assert body["days"][day] == hours

import pytest

def test_submit_timesheet_missing_2fa_code_rejected(auth_session, clean_timesheet_week):
    payload = {
        "week_start": clean_timesheet_week,
        "days": {"mon": 8, "tue": 8, "wed": 8, "thu": 8, "fri": 8, "sat": 0, "sun": 0}
    }
    resp = auth_session.post("/timesheets/submit", json=payload)
    assert resp.status_code in (401, 422)
    body = resp.json()
    body_str = str(body).lower()
    assert "two_factor" in body_str or "2fa" in body_str or "otp" in body_str or "authentication" in body_str
